create table ingredients(id integer NOT NULL,name VARCHAR(255) CONSTRAINT df_ingredients_name DEFAULT 'unnamed' not null,CONSTRAINT pk_ingredients PRIMARY KEY(id),CONSTRAINT uq_ingredients_name UNIQUE(name));
create table recipes(id integer NOT NULL,name VARCHAR( 255 ) CONSTRAINT df_recipes_name DEFAULT 'untitled' NOT NULL,description VARCHAR(1000) CONSTRAINT df_recipes_description DEFAULT NULL NULL,CONSTRAINT pk_recipes PRIMARY KEY( id ));
create table recipe_ingredients(recipe_id integer NOT NULL,ingredient_id integer NOT NULL,quantity NUMERIC(10,2) NOT NULL,CONSTRAINT pk_recipe_ingredients PRIMARY KEY(recipe_id,ingredient_id),CONSTRAINT fk_recipe_ingredients_recipe FOREIGN KEY(recipe_id) REFERENCES recipes(id),CONSTRAINT fk_recipe_ingredients_ingredient FOREIGN KEY(ingredient_id) REFERENCES ingredients(id),CONSTRAINT chk_recipe_ingredients_quantity CHECK(quantity>0));
create table documents(id int not null,title nvarchar(255) not null,body nvarchar(MAX) null,content varbinary(max) null,summary varchar(MAX) null,CONSTRAINT pk_documents PRIMARY KEY(id));
create table orders(id int IDENTITY not null,code int IDENTITY(100,10) not null,CONSTRAINT pk_orders PRIMARY KEY(id));
create table order_lines(id int not null,unit_price decimal(10,2) not null,quantity int not null,total AS unit_price * quantity,total_persisted AS unit_price * quantity PERSISTED,total_not_null AS unit_price * quantity PERSISTED NOT NULL,CONSTRAINT pk_order_lines PRIMARY KEY(id));

CREATE TABLE users (username NVARCHAR(50) COLLATE SQL_Latin1_General_CP1_CI_AS NOT NULL, email VARCHAR(100) COLLATE Latin1_General_CI_AS NULL);
